			name:      "nil pointer yields invalid pgtype.Date",
			input:     nil,
			wantValid: false,
		},
		{
			name:      "non-nil time",
			input:     &ref,
			wantValid: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := timeToPgtypeDate(tt.input)
			if got.Valid != tt.wantValid {
